const express = require('express');
const fetch = require('node-fetch');
const app = express();

// Simple BFF / Gateway that composes two services
app.get('/dashboard/:userId', async (req, res) => {
  const userId = req.params.userId;
  try {
    const [profileResp, ordersResp] = await Promise.all([
      fetch(`http://users:3000/users/${userId}`),
      fetch(`http://orders:3000/orders?user=${userId}`)
    ]);

    if (!profileResp.ok || !ordersResp.ok) return res.status(502).send('Upstream error');

    const profile = await profileResp.json();
    const orders = await ordersResp.json();

    res.json({ profile, recentOrders: orders.slice(0, 5) });
  } catch (err) {
    console.error(err);
    res.status(500).send('Gateway failure');
  }
});

app.listen(8080, () => console.log('Gateway listening on 8080'));
